import xml.etree.ElementTree as ET
from typing import Dict, Any

def validate_xml(xml_data: str) -> (bool, Dict[str, Any]):
    try:
        root = ET.fromstring(xml_data)
        
        if not isinstance(root.tag, str):
            return False, {"error": "Root tag is not a string"}
        
        for child in root:
            if not child.text and not child.attrib:
                return False, {"error": f"Child '{child.tag}' has no text or attributes"}

        return True, {}
    
    except ET.ParseError as e:
        return False, {"error": str(e)}

def main():
    xml_data = "<data><name>John</name><age>30</age></data>"
    is_valid, errors = validate_xml(xml_data)

